const LabelText = ({label, value}) =>{

	const copyToClpb  =  (v)  => {
		copyToClipboard(v);
	};

	if(!value){
		return null;
	}
	if(typeof value === "object"){
		return null;
	}
	return (
		<div className="_dsplFlx dtls">
			<div className="lbl_h_dtls">
				{label}
			</div>
			<div className="lbl_dtls" onClick={()=>copyToClpb(value)}>
				{value}
			</div>
		</div>
	) 
}

